INSERT INTO public.photos VALUES (21195, 'Paseo del Ebro c.1893', 'Imagen capturada posiblemente desde la estructura en construcciâ”œâ”‚n del nuevo puente sobre el râ”œÂ¡o Ebro que con la denominaciâ”œâ”‚n de puente de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, fue iniciado en 1887 e inaugurado en 1895. Con el fondo edilicio del barrio de La Seo y el paseo del Ebro, destaca en primer tâ”œÂ®rmino y a la izquierda, el estribo sureâ”œâ–’o del antiguo puente de Tablas o Madera. Tras â”œÂ®l, el emboque con la calle del Conde de Alperche. Hacia la derecha, del caserâ”œÂ¡o emerge el cimborrio y la torre de la Seo, seguido a continuaciâ”œâ”‚n por el Palacio Arzobispal y el Seminario Conciliar de San Valero y de San Braulio.', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65539000, -0.87388500, '0101000020E6100000F4E0EEACDDF6EBBF0E10CCD1E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50639375491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50639375491.webp', 'https://www.flickr.com/photos/zaragozaantigua/50639375491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21419, 'Convento de Jesâ”œâ•‘s c.1910', 'Imagen centrada en el puente nuevo, de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, o de Hierro, capturada desde la margen derecha del Ebro. Al fondo, la torre del antiguo convento franciscano de Nâ”¬Â¬ Sâ”¬Â¬ de Jesâ”œâ•‘s. En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65562800, -0.87081800, '0101000020E61000008194D8B5BDDDEBBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30950627624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30950627624.webp', 'https://www.flickr.com/photos/zaragozaantigua/30950627624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21475, 'Calle Palafox 1929', 'Imagen de la calle de Palafox desde la calle del Chantre, tras el derribo del antiguo edificio de la Aduana Vieja, o Casa de los Diputados del Reino. A la izquierda, el antiguo palacio de los Lazâ”œÃ­n. Al fondo, la catedral de la Seo. Justo enfrente, las casas del cabildo que fueran del Arcediano de Belchite, con la fachada que daba a la plazuela de la Aduana, desde donde se accedâ”œÂ¡a al derribado edificio. Esta demoliciâ”œâ”‚n permitiâ”œâ”‚ realinear ese lado de la calle Palafox, retranqueâ”œÃ­ndola y haciâ”œÂ®ndola mâ”œÃ­s ancha, y sobre el solar se construirâ”œÃ­ inmediatamente el Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat. Fuente visual: Archivo Josâ”œÂ® Galiay (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65403600, -0.87439400, '0101000020E61000002B323A2009FBEBBF0D349F73B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700854338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700854338.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700854338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21477, 'Calle Sepulcro 1925', 'Foto Roisin, 1925. Toma de la torre de la Seo desde la confluencia de la calle del Sepulcro con el callejâ”œâ”‚n de Ezmir, con su palacio homâ”œâ”‚nimo, de Esmir o de los marqueses de Almonacid, a la derecha.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65464000, -0.87397100, '0101000020E610000098E0D40792F7EBBFA453573ECBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14798514377.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14798514377.webp', 'https://www.flickr.com/photos/zaragozaantigua/14798514377/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21480, 'Aduana Vieja 1929', 'Imagen de la Plaza o Plazuela de la Aduana, a la izquierda, y la portada de ingreso a la "Aduana Vieja", antigua Casa de hospedaje de la Diputaciâ”œâ”‚n del Reino para diputados foranos de Zaragoza. La callecita de la derecha, antigua del "General del Reino", luego "Palafox", conectaba esta plaza con la Plaza del Reino, y la calle del Chantre, al fondo de la imagen. A la derecha, fuera de plano, el Palacio del Marquâ”œÂ®s de Lazâ”œÃ­n. Esta imagen estâ”œÃ­ datada oficialmente en 1949, aunque es improbable que esa sea la fecha: en 1929 se acometieron obras para una nueva alineaciâ”œâ”‚n de la calle Palafox (ensanchamiento), y de un aâ”œâ–’o despuâ”œÂ®s (1930) es el proyecto de Marcelino Carquâ”œÂ® para el nuevo "Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat", escuela municipal levantada en la esquina de Palafox con la calle del Chantre (luego San Vicente de Paâ”œâ•‘l), ocupando todo el espacio del muro de la imagen, el solar del antigua Aduana, y la mayor parte de la plazuela. La imagen parece realizada, por todo ello, en el tiempo de otras imâ”œÃ­genes de esta zona (Julio Requejo, Miguel Faci, Antâ”œâ”‚nio Passaporte). Fuente visual: Archivo Mora. Ayuntamiento de Zaragoza. "Antigua Aduana. Calle de Palafox".', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65399600, -0.87433500, '0101000020E6100000EDF0D7648DFAEBBF7FDB1324B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14957567152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14957567152.webp', 'https://www.flickr.com/photos/zaragozaantigua/14957567152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21481, 'Antigua Aduana 1929', '"Portada Antigua Aduana. Calle de Palafox". Antigua Casa de los Diputados (foranos) del Reino, frente al Palacio de Palafox, que queda a su derecha. Fuente visual: Ayuntamiento de Zaragoza/Archivo Mora.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65402800, -0.87437300, '0101000020E61000004D2CF015DDFAEBBF8A558330B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14958019132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14958019132.webp', 'https://www.flickr.com/photos/zaragozaantigua/14958019132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21538, 'Paseo del Ebro 1922', 'Dibujo de Dâ”œÂ¡az Domâ”œÂ¡nguez del paseo del Ebro a la altura del Palacio Arzobispal (derecha). Al fondo, la Seo. Fuente: La Cadiera 114, 1957.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65552600, -0.87444400, '0101000020E61000009CDEC5FB71FBEBBFBFD6A546E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19870797930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19870797930.webp', 'https://www.flickr.com/photos/zaragozaantigua/19870797930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21543, 'Soto del Caâ”œâ–’ar 1925', 'Zaragoza desde el soto del Caâ”œâ–’ar, Lucien Roisin, 1925. Vista de Zaragoza desde el soto del Caâ”œâ–’ar, con el puente del Pilar o de Hierro al fondo. Se pueden ver las torres de San Nicolâ”œÃ­s, la Seo (bajo la cual, los restos del estribo derecho del puente de Tablas) y el Pilar. Fuente: "Zaragoza, aâ”œâ–’os veinte. 81 fotografâ”œÂ¡as de Roisin (1925-1931)", Instituciâ”œâ”‚n Fernando el Catâ”œâ”‚lico, 2014.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65567700, -0.86822200, '0101000020E6100000E65DF58079C8EBBFA4DE5339EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20095777311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20095777311.webp', 'https://www.flickr.com/photos/zaragozaantigua/20095777311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21558, 'Aduana Vieja 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Antiguo edificio de la Aduana, en la plaza del Reino" (sic). Imagen de la Plaza o Plazuela de la Aduana, a la izquierda, y la portada de ingreso a la "Aduana Vieja", antigua Casa de hospedaje de la Diputaciâ”œâ”‚n del Reino para diputados foranos de Zaragoza, y luego pluriempleada como almacâ”œÂ®n, retâ”œÂ®n militar, y aun de bomberos. La callecita de la derecha, antigua del "General del Reino", luego "Palafox", conectaba esta plaza con la Plaza del Reino, y la calle del Chantre, al fondo de la imagen. A la derecha, fuera de plano, el Palacio del Marquâ”œÂ®s de Lazâ”œÃ­n. Las caballerâ”œÂ¡as son dirigidas hacia la doble plaza de San Bruno. Unos pocos aâ”œâ–’os despuâ”œÂ®s (1929-30) este edificio serâ”œÃ­ derribado para ensanchar la calle, y construir sobre su solar el nuevo "Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat". Fuente visual: Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œÃ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65440600, -0.87472000, '0101000020E6100000210725CCB4FDEBBF31276893C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21768175313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21768175313.webp', 'https://www.flickr.com/photos/zaragozaantigua/21768175313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21570, 'Calle de Pallaruelo, c.1929', '"Zaragoza. Calle del Pallazuelo." (sic) La antigua e irregular calle de Pallaruelo, en el barrio del Boterâ”œâ”‚n, venâ”œÂ¡a a ser la natural continuidad de la calle de Gavâ”œÂ¡n, pasada la del Sepulcro, si bien terminaba en un fondo de saco sin conexiâ”œâ”‚n directa con el paseo del Ebro. Para salir de ella habâ”œÂ¡a que tomar la calleja del Retiro y enlazar con la del Garro para desembocar en la del Conde Alperche, que sâ”œÂ¡ tenâ”œÂ¡a salida a la ribera. La otra opciâ”œâ”‚n era volverse por donde se habâ”œÂ¡a entrado. El nombre de Pallaruelo, antes Bual, le fue dado por el paisano que, enriquecido tras la batalla de Zaragoza de 1710, mediante el despojo de cuanto cadâ”œÃ­ver se le puso por delante, pudo comprarse una casa en esta câ”œÂ®ntrica zona de la ciudad. Esta calle perdurâ”œâ”‚, en forma y fondo, hasta que la remodelaciâ”œâ”‚n de la zona supuso su alineamiento ortogonal y apertura por Echegaray y Caballero. Entonces, fue redenominada "Boterâ”œâ”‚n". En la imagen, vista de la calle desde su entrada por la del Sepulcro. Al fondo, hacia la izquierda, el fondo de saco de su final, y la conexiâ”œâ”‚n con la calle del Retiro. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65444700, -0.87320800, '0101000020E6100000D06053E751F1EBBF8FFB56EBC4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23785233172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23785233172.webp', 'https://www.flickr.com/photos/zaragozaantigua/23785233172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21572, 'Calle de Monserrate c.1929', '"Zaragoza. Calle de Monserrate." La antigua calle de Monserrate recibâ”œÂ¡a ese nombre por el importante postigo del mismo nombre que se abrâ”œÂ¡a a la ribera y daba conexiâ”œâ”‚n con la calle del Sepulcro. De traza irregular, era "paralela" a la calle de Pallaruelo, y presentaba un peculiar ensanchamiento denominado "del Lobo". Esta calle perdurâ”œâ”‚ hasta que la reordenaciâ”œâ”‚n urbanâ”œÂ¡stica de la zona supuso su desapariciâ”œâ”‚n. En la imagen, vista de la calle desde su estrecha entrada por la del Sepulcro. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65426200, -0.87295000, '0101000020E6100000E561A1D634EFEBBFFE8172DBBED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23867860796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23867860796.webp', 'https://www.flickr.com/photos/zaragozaantigua/23867860796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21602, 'Puente de Hierro c.1920', 'Imagen del puente sobre el râ”œÂ¡o Ebro levantado en 1895 donde, aproximadamente, estuviera el antiguo puente de Tablas. Fue realizado en materiales mucho mâ”œÃ­s perdurables que las antiguas versiones en madera, siempre a merced de los desmadres de un râ”œÂ¡o natural. Como no podâ”œÂ¡a ser de otra forma en esta ciudad, recibiâ”œâ”‚ la corporativa denominaciâ”œâ”‚n de "Nâ”¬Â¬ Sâ”¬Â¬ del Pilar", si bien el comâ”œâ•‘n se refiere a â”œÂ®l con mâ”œÃ­s utilitarismo: es el puente "de Hierro", para diferenciarlo del "de Piedra" caracoleâ”œâ–’a. En la imagen, capturada desde la margen izquierda, el puente queda contrastado por el modesto fondo de la antigua parroquia de San Nicolâ”œÃ­s (con detalle de la sede de la Cruz Roja), y la barriada de las Taâ”œâ–’erâ”œÂ¡as. En el centro, despuntan la torre de San Nicolâ”œÃ­s y, por un capricho visual, la de la Magdalena. Fuente visual: Archivo Coyne, en "Zaragoza dos milenios de agua", Carlos Blâ”œÃ­zquez.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26255917471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26255917471.webp', 'https://www.flickr.com/photos/zaragozaantigua/26255917471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21632, 'Calle Sepulcro 1922', 'Dibujo de Dâ”œÂ¡az Domâ”œÂ¡nguez de la calle del Sepulcro en 1922, con la torre de la Seo al fondo y el palacio de Esmir a la derecha. Fuente: Revista La Cadiera.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65471400, -0.87396000, '0101000020E61000009D6340F67AF7EBBFDE1D19ABCDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42289443685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42289443685.webp', 'https://www.flickr.com/photos/zaragozaantigua/42289443685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21913, 'Calle del Sepulcro 1932', 'Imagen capturada en el tramo de la calle del Sepulcro que se ensanchaba de forma notable junto a la casa de los Esmir, cuya fachada queda a la derecha. Al fondo emerge la gran torre barroca de la Seo.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65496600, -0.87414200, '0101000020E6100000C8EBC1A4F8F8EBBFF8FE06EDD5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52507636009.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52507636009.webp', 'https://www.flickr.com/photos/zaragozaantigua/52507636009/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21950, 'Calle de Arcedianos 1949', 'Irrepetible captura de la antigua calle de Arcedianos, cuando aâ”œâ•‘n era reflejo de la abigarrada calleja que conectaba la doble plaza de San Bruno con la calle del Chantre. La calle del Chantre (a la derecha) ya no existâ”œÂ¡a, pues habâ”œÂ¡a sido sustituida por un moderno vial para vehâ”œÂ¡culos (San Vicente de Paâ”œâ•‘l), mas aâ”œâ•‘n quedaban en pie los edificios de la calle, con trazas desde del siglo XVI en adelante, que culminaban, casi tocando a la sacristâ”œÂ¡a de la Seo (al fondo), en la antigua Hospederâ”œÂ¡a de la Cartuja de la Concepciâ”œâ”‚n, cuya imagen de San Bruno, en una hornacina sobre la puerta, daba nombre a la irregular plaza del mismo nombre. La desconsideraciâ”œâ”‚n para con el patrimonio que no fue afectado por los dos sitios de 1808-1809, convirtiâ”œâ”‚ en potencial carne de derribo a todo aquel edificio que no tuviera incrustada una bala francesa (o espaâ”œâ–’ola, quâ”œÂ® mâ”œÃ­s da), como es el caso. Nada queda de esta vista, salvo la Seo, al fondo, y una plaza de San Bruno endurecida, recrecida y convertida en ocasional mercado y escenario de conciertos. Fuente visual: Archivo Municipal, Archivo Mora, 1949.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65461300, -0.87459300, '0101000020E6100000D8EF8975AAFCEBBFAA44D95BCAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18557291260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18557291260.webp', 'https://www.flickr.com/photos/zaragozaantigua/18557291260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21985, 'Calle Sepulcro C.1949', 'Dibujo de Esteban representando la calle del Sepulcro, con el palacio de Esmir a la derecha y la torre de la Seo al fondo. Fuente: www.facebook.com/photo.php?fbid=1156035214477222&set=...', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65491800, -0.87462500, '0101000020E6100000B0726891EDFCEBBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29122370861.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29122370861.webp', 'https://www.flickr.com/photos/zaragozaantigua/29122370861/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22038, 'Muralla indâ”œÂ¡gena 1990', 'Muralla indâ”œÂ¡gena de Salduie, aparecida en 1990 en la excavaciâ”œâ”‚n de la calle del Sepulcro 1 -15, solar del antiguo palacio de Esmir, en el entorno de la plaza de San Bruno correspondiente a los aledaâ”œâ–’os noroccidentales de la plaza porticada identificada con el posterior foro comercial romano. Se conservan 34 metros de longitud y 1 metro de altura. Es de yeso alabastrino y tiene una orientaciâ”œâ”‚n este-oeste, paralela al curso del Ebro, del que dista ocho metros. Forma parte del lienzo norte de la muralla de Salduie, resultando uno de los hallazgos mâ”œÃ­s importantes de la arqueologâ”œÂ¡a zaragozana. Al fondo, el palacio Arzobispal. Fuente visual: Zaragoza. prehistoria y arqueologâ”œÂ¡a. Ayuntamiento de Zaragoza, 1991.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65525400, -0.87461400, '0101000020E6100000B6F5D37FD6FCEBBF5E49F25CDFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14971051956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14971051956.webp', 'https://www.flickr.com/photos/zaragozaantigua/14971051956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22067, 'Maderas Nicolâ”œÃ­s Hermanos 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Puente del Pilar." El negocio de maderas para la construcciâ”œâ”‚n de la empresa "Nicolâ”œÃ­s Hermanos" arranca en la dâ”œÂ®cada de los 80 del XIX. En 1900 construyeron sus propios locales en el Paseo del Ebro nâ”¬â•‘ 70 (Barrio de las Tenerâ”œÂ¡as), en un solar contiguo al nuevo puente de hierro del Pilar, que inauguraron en 1901. La nueva planta se componâ”œÂ¡a de dos naves y un notable edificio destinado a vivienda y oficinas. El cartel anunciador informaba "Maderas y serrerâ”œÂ¡a Nicolâ”œÃ­s Hermanos". Allâ”œÂ¡ estuvieron hasta que la fâ”œÃ­brica fue piqueteada. Al fondo, el puente de Hierro. En el suelo, los raâ”œÂ¡les de la lâ”œÂ¡nea de tranvâ”œÂ¡a del Gâ”œÃ­llego, hacia el puente, con la derivaciâ”œâ”‚n hacia la izquierda de la Lâ”œÂ¡nea de Circunvalaciâ”œâ”‚n. En primer plano, el edificio central de la fâ”œÃ­brica, muy prâ”œâ”‚ximo a la plaza de Tenerâ”œÂ¡as.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65379500, -0.87158900, '0101000020E6100000FEB4519D0EE4EBBFE8A4F78DAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085373488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085373488.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085373488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22077, 'San Nicolâ”œÃ­s aâ”œâ–’os 50', 'Archivo Municipal. Gerardo Sancho Ramo. Aâ”œâ–’os 50. Plazuela de San Nicolâ”œÃ­s, con la iglesia de San Nicolâ”œÃ­s de Bari, en la calle del Sepulcro.', 1950, 1950, 1959, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15688929496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15688929496.webp', 'https://www.flickr.com/photos/zaragozaantigua/15688929496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22084, 'Plazuela de San Nicolâ”œÃ­s c.1950', 'Plazuela de San Nicolâ”œÃ­s con imagen de la fachada y torrecilla campanario de la barroca iglesia de San Nicolâ”œÃ­s de Bari, junto al convento de las Madres Comendadoras Canonesas Regulares del Santo Sepulcro. Un rincâ”œâ”‚n de la antigua Zaragoza que perdura, salvo las viviendas de la izquierda, desaparecidas en reformas posteriores. Fuente visual: Archivo Coyne, AHPZ.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16331827354.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16331827354.webp', 'https://www.flickr.com/photos/zaragozaantigua/16331827354/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22227, 'Râ”œÂ¡o Ebro 1954', 'Imagen capturada desde el Puente de Hierro y centrada en la inmediata ribera de la margen derecha del râ”œÂ¡o Ebro. En primer tâ”œÂ®rmino destacan los restos del antiguo estribo sur del Puente de Tablas (desaparecido definitivamente durante la riada de 1801). Por encima emerge la barroca torre y el cimborrio mudâ”œÂ®jar de la catedral del Salvador en su Epifanâ”œÂ¡a. En el centro de la escena, los dos torreones del Palacio Arzobispal, la estructura en obras de la nueva Casa Consistorial, y el templo del Pilar, con las dos torres ribereâ”œâ–’as en construcciâ”œâ”‚n. Hacia la derecha, el Puente de Piedra, sobre el que transita un tranvâ”œÂ¡a de la serie de los 40 en servicio en la lâ”œÂ¡nea 9. Gâ”œÃ­llego, antes de ser sustituida por una nueva lâ”œÂ¡nea de trolebuses; a su izquierda, una composiciâ”œâ”‚n motor+remolque de la serie 100 de la tranviaria lâ”œÂ¡nea 10. Academia.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65595200, -0.87218900, '0101000020E61000004BCADDE7F8E8EBBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49300702786.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49300702786.webp', 'https://www.flickr.com/photos/zaragozaantigua/49300702786/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22300, 'Arco del Deâ”œÃ­n 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Abril 1968. Aprovechando el derribo de un edificio anexo a las dependencias arzobispales de la calle Deâ”œÃ­n, y al que tambiâ”œÂ®n se podâ”œÂ¡a acceder por un aâ”œÂ®reo pasaje, se tomâ”œâ”‚ esta imagen del Arco y Casa del Deâ”œÃ­n de la Seo (restaurados la dâ”œÂ®cada anterior) desde una perspectiva interesante. Al fondo, la esquina de la calle de Palafox.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65491800, -0.87462500, '0101000020E6100000B0726891EDFCEBBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15546947427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15546947427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15546947427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22420, 'Coso Bajo 1967', 'Imagen capturada en el tramo final del Coso Bajo, junto a las Tenerâ”œÂ¡as, durante el paso de la banda de mâ”œâ•‘sica de la 8.â”¬Â¬ Divisiâ”œâ”‚n de Infanterâ”œÂ¡a del ejâ”œÂ®rcito de los Estados Unidos de Amâ”œÂ®rica del Norte, que participarâ”œÂ¡a en las Fiestas de Primavera de ese aâ”œâ–’o. Esta unidad militar, estacionada habitualmente en territorio de la Repâ”œâ•‘blica Federal de Alemania, recayâ”œâ”‚ temporalmente en Zaragoza por su participaciâ”œâ”‚n en las maniobras conjuntas con el ejâ”œÂ®rcito espaâ”œâ–’ol denominadas Pathfinder Express, desarrolladas en diversas localizaciones de Zaragoza, Calatayud y Daroca, y en las que la base aâ”œÂ®rea de Valenzuela tuvo un papel fundamental. La Pathfinder Express se basaba en el supuesto de que la naciâ”œâ”‚n imaginaria de "Iberia" era invadida por una "Repâ”œâ•‘blica Agresora", de forma que el Gobierno de Iberia pedâ”œÂ¡a apoyo militar al Gobierno de "Iberia occidental", que se lo concedâ”œÂ¡a para repeler la agresiâ”œâ”‚n. El General Mayor Cassidy, comandante de la 8.â”¬Â¬ Divisiâ”œâ”‚n de infanterâ”œÂ¡a norteamericana participante en esa operaciâ”œâ”‚n, habâ”œÂ¡a desembarcado en 1944 en Normandâ”œÂ¡a como miembro de la 101.â”¬Â¬ divisiâ”œâ”‚n aerotransportada para luchar contra los nazis. El Capitâ”œÃ­n General Muâ”œâ–’oz Grandes, asistente a estas maniobras en su calidad de vicepresidente del Gobierno espaâ”œâ–’ol, lucâ”œÂ¡a la Cruz de Caballero de la Cruz de Hierro con hojas de roble que le fue concedida personalmente por Adolf Hitler por comandar la Divisiâ”œâ”‚n Azul partâ”œÂ¡cipe de la agresiâ”œâ”‚n nazi a la URSS. En la imagen, a la izquierda, las traseras del Real Monasterio de Comendadoras Canonesas de la Orden Militar y Pontificia del Santo Sepulcro, integrado en un paâ”œâ–’o de las antiguas murallas de piedra de la ciudad. Sobre el firme, rieles de la antigua lâ”œÂ¡nea tranviaria 12 Barrio de Jesâ”œâ•‘s. Fuente visual: Jarke/Jaria, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65413700, -0.87187000, '0101000020E6100000F5A10BEA5BE6EBBF410DDFC2BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26741753949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26741753949.webp', 'https://www.flickr.com/photos/zaragozaantigua/26741753949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22514, 'Puente de Hierro c.1965', 'Imagen capturada junto al cuartel de automovilismo de las Tenerâ”œÂ¡as. Al fondo, el puente de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, sobre el que se dispone a cruzar una motocicleta. Destaca el tendido tranviario tambiâ”œÂ®n utilizado por trolebuses.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65417200, -0.87151400, '0101000020E61000005532005471E3EBBFBEFA78E8BBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51356559226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51356559226.webp', 'https://www.flickr.com/photos/zaragozaantigua/51356559226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22680, 'Puente de Hierro 1970', 'Imagen capturada desde el Puente de Hierro durante las obras de restauraciâ”œâ”‚n de su desgastado firme, que aquâ”œÂ¡ se muestra transparente y produce vertiginosas sensaciones, tal que si de un felino caminando sobre un cristal se tratase. Al fondo, entre, y sobre, la metâ”œÃ­lica barandilla, las instalaciones fabriles de una familiar e influyente empresa local de colchones, en el barrio de Jesâ”œâ•‘s, unos aâ”œâ–’os antes de trasladarse a la carretera de Logroâ”œâ–’o. Bajo del puente, un Ebro de aguas tranquilas fluye presocrâ”œÃ­ticamente hacia el Mediterrâ”œÃ­neo. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Referencia: ES. 50297. AM 04.01.02.13 Sobre 118267', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65628200, -0.87028900, '0101000020E61000008331225168D9EBBF0B7A6F0C01D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26311542452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26311542452.webp', 'https://www.flickr.com/photos/zaragozaantigua/26311542452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22725, 'Puente de Hierro 1972', 'Foto centrada en la unidad 201 de la lâ”œÂ¡nea 35 de los autobuses urbanos, "Verâ”œâ”‚nica-Arrabal". Estâ”œÃ­ circulando por el puente del Pilar o de Hierro, en direcciâ”œâ”‚n a la margen izquierda. Fuente: Colecciâ”œâ”‚n Daniel Andrâ”œÂ®s.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65562800, -0.87081800, '0101000020E61000008194D8B5BDDDEBBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30552364404.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30552364404.webp', 'https://www.flickr.com/photos/zaragozaantigua/30552364404/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22793, 'Calle del Sepulcro c.1978', 'Vista de los grandes solares resultantes de los derribos realizados la dâ”œÂ®cada anterior en el entorno de la calle del Sepulcro, del palacio Arzobispal (a la derecha, con la fachada en reformas) y de la pequeâ”œâ–’a plaza de San Bruno (a la izquierda, inmediata a la Seo). El solar de la derecha es el de la antigua y gran casa de los Esmir, y el de la izquierda el que en tiempos albergara el hospicio de la Cartuja de la Concepciâ”œâ”‚n y la carnicerâ”œÂ¡a del Cabildo. La imagen ha sido capturada posiblemente desde la altura del nâ”¬â•‘ 49 de la calle de San Vicente de Paâ”œâ•‘l. De fondo escâ”œÂ®nico, la iglesia metropolitana del Salvador en su Epifanâ”œÂ¡a. Tras ella, despuntan hitos verticales como la câ”œâ•‘pula del Banco Zaragozano, la torre de San Gil, el Edificio Ebrosa, la torre de San Pablo y las de Santa Isabel. A la derecha, la torre de Nuestra Seâ”œâ–’ora del Pilar del homâ”œâ”‚nimo templo.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65509600, -0.87481700, '0101000020E6100000BE839F3880FEEBBFC6DE8B2FDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41676464952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41676464952.webp', 'https://www.flickr.com/photos/zaragozaantigua/41676464952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23003, 'Râ”œÂ¡o Ebro aâ”œâ–’os 90', 'Vista del râ”œÂ¡o Ebro a su paso por Zaragoza. En primer tâ”œÂ®rmino, puente de Piedra y torre noreste del Pilar. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1990, 1990, 1999, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65639800, -0.87268500, '0101000020E61000005BB6D61709EDEBBF759483D904D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27385635046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27385635046.webp', 'https://www.flickr.com/photos/zaragozaantigua/27385635046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23209, 'Puente de Hierro 2010', 'Foto: Carlos Moncâ”œÂ¡n. Mayo de 2010. Obras de restauraciâ”œâ”‚n y cambio de color del puente de Nuestra Seâ”œâ–’ora del Pilar, vulgo de Hierro. El "verde tradicional" que habâ”œÂ¡a sustituido en los aâ”œâ–’os setenta al gris, se trocâ”œâ”‚ por el azul y blanco, tras una consulta populista. Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65577200, -0.87071100, '0101000020E6100000008FA850DDDCEBBFF6D03E56F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33225069960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33225069960.webp', 'https://www.flickr.com/photos/zaragozaantigua/33225069960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23437, 'Aduana Vieja 1922', 'Fachada del edificio donde estaba ubicado el primer retâ”œÂ®n de Bomberos de Zaragoza, en la plazuela de la Aduana, junto a la calle de Palafox. La antigua Casa de los Diputados del Reino fue construida en el siglo XVI por Marcos de Maâ”œâ–’aria, y comprada en 1590 para estancia temporal en Zaragoza de los diputados no residentes. En el siglo XIX, ya propiedad del Ayuntamiento pasâ”œâ”‚ a denominarse Aduana Vieja, con usos varios, incluyendo alojamiento de un retâ”œÂ®n militar, depâ”œâ”‚sito municipal, câ”œÃ­rcel y cuartelillo, y retâ”œÂ®n de bomberos. Un acta municipal de 1862 indica que el edificio estâ”œÃ­ en ruina, y al aâ”œâ–’o siguiente el retâ”œÂ®n de bomberos es desalojado. En 1863-64 el edificio es parcialmente derribado, y el resto perdura hasta la reordenaciâ”œâ”‚n de la calle a finales de la dâ”œÂ®cada de los aâ”œâ–’os 20, y principios de la de los 30. Quedan restos del patio interior, recompuestos en desordenado tetris, en el Museo de Zaragoza. Fuente visual: Julio Requejo.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65399100, -0.87437800, '0101000020E6100000BFF04A92E7FAEBBF6D7022FAB5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14771318117.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14771318117.webp', 'https://www.flickr.com/photos/zaragozaantigua/14771318117/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23445, 'Plaza del Reino 1930', 'Ayuntamiento de Zaragoza/Archivo Mora, 1930 Sede de la Real Sociedad Econâ”œâ”‚mica Aragonesa de Amigos del Paâ”œÂ¡s, en la plaza del Reino 5 de Zaragoza. De 1876 a 1905, sede tambiâ”œÂ®n de la Caja de Ahorros de Zaragoza. En esa misma plaza se encontraban ademâ”œÃ­s la Real Academia de Nobles y bellas Artes de San Luis (1792) y el Seminario de Pobres de San Francisco de Paula (1886).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65401300, -0.87439500, '0101000020E6100000422619390BFBEBBF5514AFB2B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14982089722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14982089722.webp', 'https://www.flickr.com/photos/zaragozaantigua/14982089722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
