INSERT INTO public.photos VALUES (23486, 'Plaza del Reino 1881', 'Grabado que reproduce de forma parcial el patio de la "Escuela de Artes y Oficios en Zaragoza", sita en la antigua Casa del Rey recayente a la plazuela o plaza del Reino, que desde finales del siglo XVIII era la sede de la Sociedad Econâ”œâ”‚mica de Amigos del Paâ”œÂ¡s, bajo cuyo impulso habâ”œÂ¡a sido constituida. Aâ”œâ–’os despuâ”œÂ®s conocerâ”œÂ¡a el inicio de una nueva â”œÂ®poca en un moderno y estiloso edificio de la antigua huerta de Santa Engracia construido al albur de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908.', 1881, 1881, 1881, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65380300, -0.87446400, '0101000020E610000063F030ED9BFBEBBF6B8313D1AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46846621125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46846621125.webp', 'https://www.flickr.com/photos/zaragozaantigua/46846621125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22048, 'Romareda 1956', 'Aâ”œÂ®rea vista de Isabel la Catâ”œâ”‚lica, caracterizada por campos de cultivo y las torres agrâ”œÂ¡colas en el espacio delimitado por el Cuartel Palafox, la Feria de Muestras, la "Casa Grande", el Convento de Jerusalâ”œÂ®n y el Seminario Conciliar.', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63757500, -0.90280000, '0101000020E610000088855AD3BCE3ECBFA4DFBE0E9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14869951680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14869951680.webp', 'https://www.flickr.com/photos/zaragozaantigua/14869951680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23488, 'Calle de Palafox c.1933', 'Imagen capturada en la calle del Chantre y centrada en la gran casa de los marqueses de Lazâ”œÃ­n (luego de los Palafox) sita en la antigua calle del General (luego de Palafox). A la izquierda, vista parcial de la plaza del Reino. A la derecha, la esquina del novâ”œÂ¡simo Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat, donde aparecen reunidos efectivos del Cuerpo de Seguridad y Asalto, posiblemente como consecuencia de los disturbios acontecidos durante la insurrecciâ”œâ”‚n anarquista de diciembre de 1933, que tuvo en esta zona uno de sus epicentros mâ”œÃ­s violentos.', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65400400, -0.87438900, '0101000020E6100000B96DDFA3FEFAEBBF02BA2F67B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49630271236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49630271236.webp', 'https://www.flickr.com/photos/zaragozaantigua/49630271236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23539, 'Sitio de Zaragoza 1808', 'Siâ”œÂ¿ge de Saragosse, Jules Girardet, 1906. Royal Albert Museum. En esta delirante pintura, que fue realizada un siglo despuâ”œÂ®s de los hechos que narra, podemos ver a la derecha la iglesia zaragozana de San Nicolâ”œÃ­s, ubicada en un entorno de fantasâ”œÂ¡a.', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65398600, -0.87261000, '0101000020E6100000B13385CE6BECEBBF5C0531D0B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15054009109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15054009109.webp', 'https://www.flickr.com/photos/zaragozaantigua/15054009109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23540, 'Maderas Nicolâ”œÃ­s Hermanos c.1965', 'AHPZ. Archivo fotogrâ”œÃ­fico Coyne. "Paso del Seâ”œâ–’or Atado a la Columna. Cofradâ”œÂ¡a del Seâ”œâ–’or Atado a la Columna y de Nuestra Seâ”œâ–’ora de la Fraternidad en el Mayor Dolor. Cofrades." Nocturno paso de la cofradâ”œÂ¡a con el fondo de la antigua empresa de maderas "Nicolâ”œÃ­s Hermanos", sita en el Barrio de las Tenerâ”œÂ¡as, entre la plaza del mismo nombre y el Puente de Hierro, que queda a la izquierda de la imagen.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65379500, -0.87158900, '0101000020E6100000FEB4519D0EE4EBBFE8A4F78DAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085644857.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085644857.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085644857/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23558, 'Monasterio de Santo Sepulcro 1966', 'Vista desde el Coso Bajo de las traseras del Monasterio del Santo Sepulcro y su iglesia de San Nicolâ”œÃ­s, en un conjunto construido en la antigua muralla de la ciudad. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65404100, -0.87206300, '0101000020E61000001AA721AAF0E7EBBF1F9F909DB7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22735616658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22735616658.webp', 'https://www.flickr.com/photos/zaragozaantigua/22735616658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23563, 'Plaza San Nicolâ”œÃ­s 1965', 'Vista parcial de la plaza de San Nicolâ”œÃ­s, con la calle del Sepulcro a la izquierda. A la derecha, fuera de campo, iglesia de San Nicolâ”œÃ­s. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23165553771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23165553771.webp', 'https://www.flickr.com/photos/zaragozaantigua/23165553771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23567, 'Tumultos 1705', '"Tumultos en Zaragoza contra las tropas francesas", ilustraciâ”œâ”‚n de Fernando Fernâ”œÃ­ndez Mota que prentende recrear el "motâ”œÂ¡n de Zaragoza" de 1705, cuando en el marco de la Guerra de Sucesiâ”œâ”‚n, austracistas locales, en la imagen con aires de baturros decimonâ”œâ”‚nicos, atacaron a un regimiento borbâ”œâ”‚nico francâ”œÂ®s que pasaba por la ciudad camino del frente de guerra en Cataluâ”œâ–’a. El marco elegido es la plazuela de San Nicolâ”œÃ­s, junto a la homâ”œâ”‚nima iglesia parroquial. Este episodio redundaba en la idea que presentaba al "pueblo" (concepto inexistente antes de la Revoluciâ”œâ”‚n Francesa de 1789) como globalmente partidario del bando austracista, lo que en el caso de la Zaragoza de la â”œÂ®poca es muy temerario de afirmar, dados los bandazos o cambios de banderâ”œÂ¡a que las elites locales realizaron en funciâ”œâ”‚n del sentido de la guerra. Fuente visual: Historia de Espaâ”œâ–’a, Miguel Seguâ”œÂ¡, 1910, en todocoleccion.net.', 1705, 1705, 1705, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65409700, -0.87266200, '0101000020E610000050C8CEDBD8ECEBBFB3B45373B9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27226658288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27226658288.webp', 'https://www.flickr.com/photos/zaragozaantigua/27226658288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23570, 'Monasterio del Santo Sepulcro aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste que muestra las traseras del Monasterio del Santo Sepulcro, en la antigua muralla a la salida al Ebro del Coso Bajo. Al fondo, torre de la iglesia de San Nicolâ”œÃ­s. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65387200, -0.87211700, '0101000020E6100000E62329E961E8EBBF93E2E313B2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31597369614.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31597369614.webp', 'https://www.flickr.com/photos/zaragozaantigua/31597369614/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23579, 'Tenerâ”œÂ¡as 1930', 'Imagen centrada en la isleta reciâ”œÂ®n embellecida que triangulaba el encuentro de la ribera del Ebro y las traseras del convento del Santo Sepulcro (a la derecha), el acceso al puente del Pilar, y el final del Coso Bajo. A la izquierda, los almacenes y serrerâ”œÂ¡a de Maderas Hermanos Nicolâ”œÃ­s, el ingreso a la calle de Monreal y, al fondo, la plazuela de las Tenerâ”œÂ¡as. En el extremo superior de la isleta, la garita del Fielato de las Tenerâ”œÂ¡as Fuente visual: www.mecd.gob.es/.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65413700, -0.87187000, '0101000020E6100000F5A10BEA5BE6EBBF410DDFC2BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36454484001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36454484001.webp', 'https://www.flickr.com/photos/zaragozaantigua/36454484001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23596, 'El Boterâ”œâ”‚n 1958', 'Ruinosa escena capturada durante el proceso de derribo de los antiguos inmuebles del barrio del Boterâ”œâ”‚n vertebrados por las calles del Garro, Retiro, Pallaruelo, Grillo, Monserrate y Lobo, que tras el derribo desaparecerâ”œÂ¡an del nomenclâ”œÃ­tor urbano, sustituidas por la calle del Boterâ”œâ”‚n y la plaza de N.â”¬Â¬ S.â”¬Â¬ de la Piedad. Al fondo, alzado de los modernos edificios construidos y en construcciâ”œâ”‚n en torno al final de la calle de San Vicente de Paâ”œâ•‘l, que en este tramo antes se llamara del Conde de Alperche y que a la derecha chaflanea con el paseo de Echegaray y Caballero. En primer tâ”œÂ®rmino y a la izquierda, un par de niâ”œâ–’as sentadas sobre una viga de madera de un edificio derribado, contemplan el arruinado escenario de este tradicional enclave zaragozano.', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65457800, -0.87315500, '0101000020E61000001BD82AC1E2F0EBBF2E573F36C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52138231161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52138231161.webp', 'https://www.flickr.com/photos/zaragozaantigua/52138231161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23803, 'Vista de Zaragoza 1861', 'Vista de Zaragoza desde la margen izquierda del Ebro. "La torre campanil de La Seo, andamiada, despuâ”œÂ®s de que un rayo incendiase y arruinase su chapitel (1850), permite establecer con precisiâ”œâ”‚n la cronologâ”œÂ¡a de la fotografâ”œÂ¡a, puesto que la torre permaneciâ”œâ”‚ andamiada y todavâ”œÂ¡a sin el nuevo chapitel, entre enero y marzo de 1861." Josâ”œÂ® Antonio Hernâ”œÃ­ndez Latas. Fuente: Fotâ”œâ”‚grafo: Mariano Jâ”œâ•‘dez y Ortiz, 1861. â”œÃ¼lbum de Andrâ”œÂ®s Martâ”œÂ¡n e Ipâ”œÃ­s. Colecciâ”œâ”‚n Mariano Martâ”œÂ¡n Casalderrey, Zaragoza. Libro Primeros tiempos de la fotografâ”œÂ¡a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65660300, -0.87030900, '0101000020E61000004A438D4292D9EBBF4DBA2D910BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15217164370.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15217164370.webp', 'https://www.flickr.com/photos/zaragozaantigua/15217164370/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24097, 'Calle del Sepulcro c.1959', 'Imagen capturada durante el recorrido que la procesiâ”œâ”‚n de la Cofradâ”œÂ¡a de Nuestra Seâ”œâ–’ora de la Piedad y del Santo Sepulcro realiza entre la iglesia de Santa Isabel de Portugal y la de San Nicolâ”œÃ­s de Bari la madrugada del dâ”œÂ¡a 15 de abril, como es tradicional desde 1937. La escena, centrada en el paso de la carroza de la Virgen de la Piedad diseâ”œâ–’ada por los arquitectos Regino Borobio Ojeda y Josâ”œÂ® Beltrâ”œÃ­n Navarro, tiene lugar con el fondo edilicio de la antigua casa del siglo XVI que fuera de Juan Manente, luego de los marqueses de Almonacid, y desde finales del siglo XVII de los Esmir, en el tramo de la calle del Sepulcro entre la plaza de San Bruno y la moderna calle de San Vicente de Paâ”œâ•‘l. Esta vieja casona serâ”œÂ¡a derribada aâ”œâ–’os despuâ”œÂ®s para modernizar la zona y desprovincionarla. Hemos volteado horizontalmente la original imagen para que tenga sentido arquitectâ”œâ”‚nico y visual, y la procesionaria pueda llegar correctamente a su destino.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65499800, -0.87447500, '0101000020E61000005D6DC5FEB2FBEBBF037976F9D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50117608373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50117608373.webp', 'https://www.flickr.com/photos/zaragozaantigua/50117608373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
